		{
			wall[i][j] = rand() % 10;
		}
	}
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO)
{
	int BLOCK_SIZE = cols; // We will parallelize over cols
	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

	// We will process the entire row in parallel
	// For each thread, tx is the index in [0, cols-1]
	// We simulate the local memory arrays prev and result as arrays of size BLOCK_SIZE

	int* prev = new int[BLOCK_SIZE];
	int* result = new int[BLOCK_SIZE];

	// Initialize prev with gpuSrc values for valid indices
	#pragma omp parallel for
	for (int tx = 0; tx < BLOCK_SIZE; tx++) {
		int xidx = tx;
		if (IN_RANGE(xidx, 0, cols-1)) {
			prev[tx] = gpuSrc[xidx];
		} else {
			prev[tx] = 0;
		}
	}

	// Synchronize threads (implicit barrier after parallel for)

	bool* computed_array = new bool[BLOCK_SIZE];
	for (int i = 0; i < iteration; i++)
	{
		#pragma omp parallel for
		for (int tx = 0; tx < BLOCK_SIZE; tx++) {
			computed_array[tx] = false;
		}

		#pragma omp parallel for
		for (int tx = 0; tx < BLOCK_SIZE; tx++)
		{
			int blkX = 0 - border; // Since bx=0 in this translation
			int blkXmax = blkX + BLOCK_SIZE - 1;
			int xidx = blkX + tx;

			int validXmin = (blkX < 0) ? -blkX : 0;
			int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

			int W = tx - 1;
			int E = tx + 1;

			W = (W < validXmin) ? validXmin : W;
			E = (E > validXmax) ? validXmax : E;

			bool isValid = IN_RANGE(tx, validXmin, validXmax);

			if (IN_RANGE(tx, i+1, BLOCK_SIZE - i - 2) && isValid && IN_RANGE(xidx, 0, cols-1))
			{
				computed_array[tx] = true;
				int left = prev[W];
				int up = prev[tx];
				int right = prev[E];
				int shortest = MIN(left, up);
				shortest = MIN(shortest, right);

				int index = cols*(startStep+i)+xidx;
				result[tx] = shortest + gpuWall[index];
			}
		}

		// Synchronize threads (implicit barrier after parallel for)

		if (i == iteration - 1)
		{
			break;
		}

		#pragma omp parallel for
		for (int tx = 0; tx < BLOCK_SIZE; tx++)
		{
			if (computed_array[tx])
			{
				prev[tx] = result[tx];
			}
		}

		// Synchronize threads (implicit barrier after parallel for)
	}

	// Write back results
	#pragma omp parallel for
	for (int tx = 0; tx < BLOCK_SIZE; tx++)
	{
		if (computed_array[tx] && IN_RANGE(tx, 0, cols-1))
		{
			gpuResults[tx] = result[tx];
		}
	}

	delete[] prev;
	delete[] result;
	delete[] computed_array;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO_VAL;

	int size = rows * cols;

	int* d_gpuWall = new int[size - cols];
	int* d_gpuResult[2];
	d_gpuResult[0] = new int[cols];
	d_gpuResult[1] = new int[cols];
	int* d_outputBuffer = new int[16384];

	for (int i = 0; i < 16384; i++) {
		d_outputBuffer[i] = 0;
	}

	// Copy data + cols to d_gpuWall
	for (int i = 0; i < size - cols; i++) {
		d_gpuWall[i] = data[i + cols];
	}

	// Initialize d_gpuResult[0] with data
	for (int i = 0; i < cols; i++) {
		d_gpuResult[0][i] = data[i];
	}

	int src = 1, final_ret = 0;
	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO_VAL;

		// Launch kernel equivalent
		dynproc_kernel(arg0,
		               d_gpuWall,
		               d_gpuResult[src],
		               d_gpuResult[final_ret],
		               cols,
		               rows,
		               t,
		               borderCols,
		               theHalo);
	}

	// Copy back results
	for (int i = 0; i < cols; i++) {
		result[i] = d_gpuResult[final_ret][i];
	}

	// Output buffer last char set to '\0' as in original code
	d_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	delete[] d_gpuWall;
	delete[] d_gpuResult[0];
	delete[] d_gpuResult[1];
	delete[] d_outputBuffer;

	delete[] data;
	delete[] wall;
	delete[] result;

	return EXIT_SUCCESS;
}

